import java.util.*;class A{static int W,H;static int nodes(char[][]g){int c=0;for(var r:g)for(var v:r)if(v=='@')c++;return c;}static int boom(char[][]g,int bx,int by,char[][]ng){for(int y=0;y<H;y++)ng[y]=g[y].clone();int h=0;if(ng[by][bx]=='@'){ng[by][bx]='.';h++;}int[]dx={1,-1,0,0},dy={0,0,1,-1};for(int d=0;d<4;d++)for(int i=1;i<=3;i++){int x=bx+dx[d]*i,y=by+dy[d]*i;if(x<0||x>=W||y<0||y>=H||ng[y][x]=='#')break;if(ng[y][x]=='@'){ng[y][x]='.';h++;}}return h;}static List<int[]>plan=new ArrayList<>();static boolean solve(char[][]g,int b,int t){if(nodes(g)==0)return true;if(b==0||t<3)return false;var cs=new ArrayList<int[]>();for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(g[y][x]!='#'&&g[y][x]!='@'){var ng=new char[H][];int s=boom(g,x,y,ng);if(s>0)cs.add(new int[]{-s,x,y});}cs.sort((a,b2)->a[0]-b2[0]);for(int i=0;i<Math.min(cs.size(),20);i++){var c=cs.get(i);var ng=new char[H][];boom(g,c[1],c[2],ng);plan.add(new int[]{c[1],c[2]});if(solve(ng,b-1,t-3))return true;plan.remove(plan.size()-1);}return false;}public static void main(String[]args){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();var G=new char[H][];for(int y=0;y<H;y++)G[y]=s.next().toCharArray();int pi=0;for(;;){int t=s.nextInt(),b=s.nextInt();if(pi>=plan.size())solve(G,b,t);if(pi<plan.size()){System.out.println(plan.get(pi)[0]+" "+plan.get(pi)[1]);pi++;for(int i=0;i<2;i++){s.nextInt();s.nextInt();System.out.println("WAIT");}}else System.out.println("WAIT");}}}